import React, { useState } from 'react';

const Contact: React.FC = () => {
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [message, setMessage] = useState('');
  const [sent, setSent] = useState(false);

  const inputStyle: React.CSSProperties = {
    width: '100%',
    padding: '4px 6px',
    border: '2px inset #c0c0c0',
    fontSize: 12,
    fontFamily: 'inherit',
    marginTop: 4,
    marginBottom: 12,
    outline: 'none',
  };

  const btnStyle: React.CSSProperties = {
    padding: '6px 24px',
    background: '#c0c0c0',
    borderTop: '2px solid #ffffff',
    borderLeft: '2px solid #ffffff',
    borderRight: '2px solid #404040',
    borderBottom: '2px solid #404040',
    cursor: 'pointer',
    fontSize: 12,
    fontFamily: 'inherit',
  };

  const handleSubmit = () => {
    if (!name || !email || !message) return;
    window.open(`mailto:Raghvv.bhatia@gmail.com?subject=Portfolio Contact from ${name}&body=${encodeURIComponent(`From: ${name}\nEmail: ${email}\n\n${message}`)}`);
    setSent(true);
    setName(''); setEmail(''); setMessage('');
  };

  return (
    <div style={{ padding: 24, maxWidth: 600 }}>
      <h2 style={{ fontSize: 22, borderBottom: '2px solid #c0c0c0', paddingBottom: 8, marginBottom: 20 }}>Contact</h2>

      {/* Direct contact info */}
      <div style={{ marginBottom: 24, display: 'flex', flexDirection: 'column', gap: 10 }}>
        <ContactRow icon="✉️" label="Email" value="Raghvv.bhatia@gmail.com" href="mailto:Raghvv.bhatia@gmail.com" />
        <ContactRow icon="📞" label="Phone" value="+64 21 0903 7606" href="tel:+6421090370606" />
        <ContactRow icon="💼" label="LinkedIn" value="linkedin.com/in/raghv-bhatia" href="https://www.linkedin.com/in/raghv-bhatia/" />
      </div>

      <div style={{ borderTop: '1px solid #c0c0c0', paddingTop: 20 }}>
        <h3 style={{ marginBottom: 14, fontSize: 14 }}>Send a Message</h3>
        {sent && <p style={{ color: 'green', marginBottom: 10 }}>✔ Message sent! I'll be in touch.</p>}
        <label style={{ fontSize: 12, fontWeight: 'bold' }}>Your Name *</label>
        <input style={inputStyle} value={name} onChange={e => setName(e.target.value)} placeholder="Name" />
        <label style={{ fontSize: 12, fontWeight: 'bold' }}>Email *</label>
        <input style={inputStyle} value={email} onChange={e => setEmail(e.target.value)} placeholder="Email" type="email" />
        <label style={{ fontSize: 12, fontWeight: 'bold' }}>Message *</label>
        <textarea style={{ ...inputStyle, height: 80, resize: 'vertical' }} value={message} onChange={e => setMessage(e.target.value)} placeholder="Your message..." />
        <button style={btnStyle} onClick={handleSubmit} disabled={!name || !email || !message}>Send Message</button>
      </div>
    </div>
  );
};

const ContactRow: React.FC<{ icon: string; label: string; value: string; href: string }> = ({ icon, label, value, href }) => (
  <div style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '8px 12px', background: '#f0f0f0', border: '1px solid #c0c0c0' }}>
    <span style={{ fontSize: 18 }}>{icon}</span>
    <div>
      <div style={{ fontSize: 10, color: '#555', textTransform: 'uppercase', letterSpacing: 1 }}>{label}</div>
      <a href={href} target="_blank" rel="noreferrer" style={{ fontSize: 13, color: '#000080', fontWeight: 'bold' }}>{value}</a>
    </div>
  </div>
);

export default Contact;
